mapper.select:
select sl.id as id, sl.title as title, sl.method as method, sl.business_type as businessType, sl.request_method as requestMethod, su.real_name as operateName, sl.operate_url as operateUrl, sl.operate_address as operateAddress, sl.request_param as requestParam, sl.response_body as responseBody, sl.success as success, sl.error_msg as errorMsg, sl.create_time as createTime, sl.description as description, sl.request_body as requestBody, sl.logging_type as loggingType, sl.browser as browser, sl.system_os as systemOs from sys_log sl left join sys_user su on sl.operate_name =su.username where sl.logging_type = #{loggingType}
and sl.create_time >= #{startTime}
and sl.create_time <= #{endTime}
order by sl.create_time desc
